import{_ as e,c as o,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Múltiplos Canais e Plataformas | Tutorial Clawdbot","description":"Aprenda como configurar e usar o sistema multicanal do Clawdbot, incluindo canais e plataformas como WhatsApp, Telegram, Slack, Discord, Google Chat, Signal, iMessage, LINE, WebChat, macOS, iOS e Android.","frontmatter":{"title":"Múltiplos Canais e Plataformas | Tutorial Clawdbot","sidebarTitle":"Integração com Ferramentas de Chat Comuns","subtitle":"Múltiplos Canais e Plataformas","description":"Aprenda como configurar e usar o sistema multicanal do Clawdbot, incluindo canais e plataformas como WhatsApp, Telegram, Slack, Discord, Google Chat, Signal, iMessage, LINE, WebChat, macOS, iOS e Android.","tags":["canais","plataformas","integração"],"order":60},"headers":[],"relativePath":"pt/moltbot/moltbot/platforms/index.md","filePath":"pt/moltbot/moltbot/platforms/index.md"}'),r={name:"pt/moltbot/moltbot/platforms/index.md"};function t(n,a,l,d,c,m){return s(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="multiplos-canais-e-plataformas" tabindex="-1">Múltiplos Canais e Plataformas <a class="header-anchor" href="#multiplos-canais-e-plataformas" aria-label="Permalink to &quot;Múltiplos Canais e Plataformas&quot;">​</a></h1><p>O Clawdbot suporta múltiplos canais de comunicação e plataformas através do plano de controle Gateway unificado, permitindo que você interaja com seu assistente de IA em interfaces familiares.</p><h2 id="visao-geral-do-capitulo" tabindex="-1">Visão Geral do Capítulo <a class="header-anchor" href="#visao-geral-do-capitulo" aria-label="Permalink to &quot;Visão Geral do Capítulo&quot;">​</a></h2><p>Este capítulo apresenta todos os canais de comunicação e plataformas suportados pelo Clawdbot, incluindo aplicativos de mensagens instantâneas (WhatsApp, Telegram, Slack, Discord, etc.), nós móveis (iOS, Android) e aplicativos de desktop (macOS). Aprenda como configurar esses canais para integrar perfeitamente o assistente de IA ao seu fluxo de trabalho diário.</p><h2 id="navegacao-de-subpaginas" tabindex="-1">Navegação de Subpáginas <a class="header-anchor" href="#navegacao-de-subpaginas" aria-label="Permalink to &quot;Navegação de Subpáginas&quot;">​</a></h2><h3 id="visao-geral-dos-canais" tabindex="-1">Visão Geral dos Canais <a class="header-anchor" href="#visao-geral-dos-canais" aria-label="Permalink to &quot;Visão Geral dos Canais&quot;">​</a></h3><ul><li><strong><a href="./channels-overview/">Visão Geral do Sistema Multicanal</a></strong> - Conheça todos os canais de comunicação suportados pelo Clawdbot e suas características, compreenda os conceitos básicos de configuração de canais.</li></ul><h3 id="canais-de-mensagens-instantaneas" tabindex="-1">Canais de Mensagens Instantâneas <a class="header-anchor" href="#canais-de-mensagens-instantaneas" aria-label="Permalink to &quot;Canais de Mensagens Instantâneas&quot;">​</a></h3><ul><li><strong><a href="./whatsapp/">WhatsApp</a></strong> - Configure e use o canal WhatsApp (baseado em Baileys), suporte para vinculação de dispositivo e gerenciamento de grupos.</li><li><strong><a href="./telegram/">Telegram</a></strong> - Configure e use o canal Telegram (baseado em grammY Bot API), configure Bot Token e Webhook.</li><li><strong><a href="./slack/">Slack</a></strong> - Configure e use o canal Slack (baseado em Bolt), integre ao seu espaço de trabalho.</li><li><strong><a href="./discord/">Discord</a></strong> - Configure e use o canal Discord (baseado em discord.js), suporte para servidores e canais.</li><li><strong><a href="./googlechat/">Google Chat</a></strong> - Configure e use o canal Google Chat, integre com o Google Workspace.</li><li><strong><a href="./signal/">Signal</a></strong> - Configure e use o canal Signal (baseado em signal-cli), comunicação com privacidade protegida.</li><li><strong><a href="./imessage/">iMessage</a></strong> - Configure e use o canal iMessage (exclusivo macOS), integre com o aplicativo Mensagens do macOS.</li><li><strong><a href="./line/">LINE</a></strong> - Configure e use o canal LINE (Messaging API), interaja com usuários LINE.</li></ul><h3 id="web-e-aplicativos-nativos" tabindex="-1">Web e Aplicativos Nativos <a class="header-anchor" href="#web-e-aplicativos-nativos" aria-label="Permalink to &quot;Web e Aplicativos Nativos&quot;">​</a></h3><ul><li><strong><a href="./webchat/">Interface WebChat</a></strong> - Use a interface WebChat integrada para interagir com o assistente de IA, sem necessidade de configurar canais externos.</li><li><strong><a href="./macos-app/">Aplicativo macOS</a></strong> - Conheça as funcionalidades do aplicativo da barra de menus macOS, incluindo Voice Wake, Talk Mode e controle remoto.</li><li><strong><a href="./ios-node/">Nó iOS</a></strong> - Configure o nó iOS para executar operações locais do dispositivo (Câmera, Canvas, Voice Wake).</li><li><strong><a href="./android-node/">Nó Android</a></strong> - Configure o nó Android para executar operações locais do dispositivo (Câmera, Canvas).</li></ul><h2 id="recomendacao-de-caminho-de-aprendizado" tabindex="-1">Recomendação de Caminho de Aprendizado <a class="header-anchor" href="#recomendacao-de-caminho-de-aprendizado" aria-label="Permalink to &quot;Recomendação de Caminho de Aprendizado&quot;">​</a></h2><p>Com base em seu cenário de uso, recomendamos a seguinte ordem de aprendizado:</p><h3 id="inicio-rapido-para-iniciantes" tabindex="-1">Início Rápido para Iniciantes <a class="header-anchor" href="#inicio-rapido-para-iniciantes" aria-label="Permalink to &quot;Início Rápido para Iniciantes&quot;">​</a></h3><p>Se você está usando o Clawdbot pela primeira vez, recomendamos estudar na seguinte ordem:</p><ol><li><strong><a href="./channels-overview/">Visão Geral do Sistema Multicanal</a></strong> - Primeiro, compreenda a arquitetura geral e os conceitos de canais</li><li><strong><a href="./webchat/">Interface WebChat</a></strong> - A maneira mais simples, comece a usar sem qualquer configuração</li><li><strong>Escolha um canal comum</strong> - Escolha com base em seus hábitos diários: <ul><li>Chat diário → <a href="./whatsapp/">WhatsApp</a> ou <a href="./telegram/">Telegram</a></li><li>Colaboração em equipe → <a href="./slack/">Slack</a> ou <a href="./discord/">Discord</a></li><li>Usuários macOS → <a href="./imessage/">iMessage</a></li></ul></li></ol><h3 id="integracao-movel" tabindex="-1">Integração Móvel <a class="header-anchor" href="#integracao-movel" aria-label="Permalink to &quot;Integração Móvel&quot;">​</a></h3><p>Se você deseja usar o Clawdbot em seu dispositivo móvel:</p><ol><li><strong><a href="./ios-node/">Nó iOS</a></strong> - Configure funcionalidades locais no iPhone/iPad</li><li><strong><a href="./android-node/">Nó Android</a></strong> - Configure funcionalidades locais no dispositivo Android</li><li><strong><a href="./macos-app/">Aplicativo macOS</a></strong> - Use o aplicativo macOS como centro de controle</li></ol><h3 id="implantacao-empresarial" tabindex="-1">Implantação Empresarial <a class="header-anchor" href="#implantacao-empresarial" aria-label="Permalink to &quot;Implantação Empresarial&quot;">​</a></h3><p>Se você precisa implantar em ambiente de equipe:</p><ol><li><strong><a href="./slack/">Slack</a></strong> - Integre com o espaço de trabalho da equipe</li><li><strong><a href="./discord/">Discord</a></strong> - Estabeleça servidor comunitário</li><li><strong><a href="./googlechat/">Google Chat</a></strong> - Integre com o Google Workspace</li></ol><h2 id="pre-requisitos" tabindex="-1">Pré-requisitos <a class="header-anchor" href="#pre-requisitos" aria-label="Permalink to &quot;Pré-requisitos&quot;">​</a></h2><p>Antes de começar a estudar este capítulo, recomendamos completar:</p><ul><li><strong><a href="./../start/getting-started/">Início Rápido</a></strong> - Complete a instalação e configuração básica do Clawdbot</li><li><strong><a href="./../start/onboarding-wizard/">Configuração Guiada</a></strong> - Complete as configurações básicas do Gateway e canais através do assistente</li></ul><div class="tip custom-block"><p class="custom-block-title">Dica</p><p>Se você já completou a configuração guiada, alguns canais podem ter sido configurados automaticamente. Você pode pular etapas de configuração repetidas e ir diretamente para funcionalidades avançadas de canais específicos.</p></div><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><p>Após completar o estudo deste capítulo, você pode continuar explorando:</p><ul><li><strong><a href="./../advanced/models-auth/">Configuração de Modelos de IA e Autenticação</a></strong> - Configure diferentes provedores de modelos de IA</li><li><strong><a href="./../advanced/session-management/">Gerenciamento de Sessões e Multi-Agent</a></strong> - Aprenda isolamento de sessões e colaboração de sub-agentes</li><li><strong><a href="./../advanced/tools-browser/">Sistema de Ferramentas</a></strong> - Use automação de navegador, execução de comandos e outras ferramentas</li></ul><h2 id="perguntas-frequentes" tabindex="-1">Perguntas Frequentes <a class="header-anchor" href="#perguntas-frequentes" aria-label="Permalink to &quot;Perguntas Frequentes&quot;">​</a></h2><details class="details custom-block"><summary>Posso usar múltiplos canais simultaneamente?</summary><p>Sim! O Clawdbot suporta habilitar múltiplos canais simultaneamente. Você pode receber e enviar mensagens em diferentes canais, todas as mensagens são processadas através do Gateway unificado.</p></details><details class="details custom-block"><summary>Qual canal é mais recomendado?</summary><p>Isso depende do seu cenário de uso:</p><ul><li><strong>WebChat</strong> - O mais simples, sem necessidade de qualquer configuração</li><li><strong>WhatsApp</strong> - Adequado para conversar com amigos e familiares</li><li><strong>Telegram</strong> - API Bot estável, adequado para respostas automáticas</li><li><strong>Slack/Discord</strong> - Adequado para colaboração em equipe</li></ul></details><details class="details custom-block"><summary>Configurar canais requer pagamento?</summary><p>A maioria dos canais é gratuita, mas alguns canais podem ter custos:</p><ul><li>WhatsApp Business API - Pode gerar custos</li><li>Google Chat - Requer conta do Google Workspace</li><li>Outros canais - Geralmente gratuitos, apenas precisa solicitar Bot Token</li></ul></details>',33)])])}const g=e(r,[["render",t]]);export{p as __pageData,g as default};
